numeros = [1, 2, 2, 3, 3, 3, 4]

# set() remove os duplicados automaticamente
unicos = set(numeros)
print(unicos)          # {1, 2, 3, 4}
print(len(unicos))     # 4

# Operações de conjunto
pares = {2, 4, 6, 8}
multiplos_de_3 = {3, 6, 9}

print(pares & multiplos_de_3)   # interseção: {6}
print(pares | multiplos_de_3)   # união: todos os itens
